import{c as e,Q as r,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Patterns for Building LLM-based Systems & Products","description":"","frontmatter":{"title":"Patterns for Building LLM-based Systems & Products","authors":"Eugene Yan","source":"https://eugeneyan.com/writing/llm-patterns/","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2023-eugene-yan-llm-patterns.md","filePath":"research/agent-harness/references/2023-eugene-yan-llm-patterns.md","lastUpdated":1779796674000}'),s={name:"research/agent-harness/references/2023-eugene-yan-llm-patterns.md"};function d(l,t,o,i,h,g){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="patterns-for-building-llm-based-systems-products" tabindex="-1">Patterns for Building LLM-based Systems &amp; Products <a class="header-anchor" href="#patterns-for-building-llm-based-systems-products" aria-label="Permalink to &quot;Patterns for Building LLM-based Systems &amp; Products&quot;">​</a></h1><ul><li><strong>作者</strong>: Eugene Yan</li><li><strong>URL</strong>: <a href="https://eugeneyan.com/writing/llm-patterns/" target="_blank" rel="noreferrer">https://eugeneyan.com/writing/llm-patterns/</a></li><li><strong>發表</strong>: 2023（約）</li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>重要性</strong>: Priority B — 生產級 LLM 系統的 7 大設計模式</li></ul><hr><h2 id="_7-大-patterns" tabindex="-1">7 大 Patterns <a class="header-anchor" href="#_7-大-patterns" aria-label="Permalink to &quot;7 大 Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>核心目的</th><th>Harness 相關度</th></tr></thead><tbody><tr><td><strong>Evals</strong></td><td>評估與品質保證</td><td>⭐⭐⭐⭐⭐ 必需</td></tr><tr><td><strong>RAG</strong></td><td>檢索增強生成</td><td>⭐⭐⭐⭐ Memory 層的實現</td></tr><tr><td><strong>Fine-tuning</strong></td><td>模型專化</td><td>⭐⭐ 模型層，非 harness</td></tr><tr><td><strong>Caching</strong></td><td>重複交互優化</td><td>⭐⭐⭐⭐ Context 效率</td></tr><tr><td><strong>Guardrails</strong></td><td>輸出控制與安全</td><td>⭐⭐⭐⭐⭐ 必需</td></tr><tr><td><strong>Defensive UX</strong></td><td>防禦性交互設計</td><td>⭐⭐⭐ 使用者界面層</td></tr><tr><td><strong>Collect User Feedback</strong></td><td>持續改進迴路</td><td>⭐⭐⭐⭐ Ratchet 的外部信號</td></tr></tbody></table><hr><h2 id="核心洞見-對-harness-engineering-最相關" tabindex="-1">核心洞見（對 Harness Engineering 最相關） <a class="header-anchor" href="#核心洞見-對-harness-engineering-最相關" aria-label="Permalink to &quot;核心洞見（對 Harness Engineering 最相關）&quot;">​</a></h2><h3 id="_1-專化模型組隊優於單一通才" tabindex="-1">1. 專化模型組隊優於單一通才 <a class="header-anchor" href="#_1-專化模型組隊優於單一通才" aria-label="Permalink to &quot;1. 專化模型組隊優於單一通才&quot;">​</a></h3><p>多個小型專化模型的組合（用提示鏈式串接）在許多任務上優於單一大型通才模型。</p><ul><li><strong>Harness 意義</strong>: 子任務路由到最合適的 agent/skill，而非全部交給同一個 agent</li></ul><h3 id="_2-hybrid-方法優於單一最優策略" tabindex="-1">2. Hybrid 方法優於單一最優策略 <a class="header-anchor" href="#_2-hybrid-方法優於單一最優策略" aria-label="Permalink to &quot;2. Hybrid 方法優於單一最優策略&quot;">​</a></h3><p>Hybrid Retrieval（傳統搜尋 + embedding 搜尋）的組合效果優於任一單一方法。</p><ul><li><strong>Harness 意義</strong>: 多層次決策機制（tools + context + memory）比單一路徑更可靠</li></ul><h3 id="_3-guardrails-和-evals-是生產環境的必需品" tabindex="-1">3. Guardrails 和 Evals 是生產環境的必需品 <a class="header-anchor" href="#_3-guardrails-和-evals-是生產環境的必需品" aria-label="Permalink to &quot;3. Guardrails 和 Evals 是生產環境的必需品&quot;">​</a></h3><p>系統化的評估框架和輸出守衛，不是可選的優化。</p><ul><li><strong>Harness 意義</strong>: verification loop 和 error handling 必須內建，而非事後添加</li></ul><h3 id="_4-數據與反饋是競爭護城河" tabindex="-1">4. 數據與反饋是競爭護城河 <a class="header-anchor" href="#_4-數據與反饋是競爭護城河" aria-label="Permalink to &quot;4. 數據與反饋是競爭護城河&quot;">​</a></h3><p>用戶反饋收集機制是長期持續改進的關鍵。</p><ul><li><strong>Harness 意義</strong>: 每次 agent 失敗都是 Ratchet 改進的原料；需要系統性收集</li></ul><h3 id="_5-實施細節影響巨大" tabindex="-1">5. 實施細節影響巨大 <a class="header-anchor" href="#_5-實施細節影響巨大" aria-label="Permalink to &quot;5. 實施細節影響巨大&quot;">​</a></h3><p>提示措辭、tokenization 策略等細節會導致模型排名大幅波動。</p><ul><li><strong>Harness 意義</strong>: Harness 的每一行配置都可能影響整體性能分布</li></ul><hr><h2 id="與-harness-設計的對應" tabindex="-1">與 Harness 設計的對應 <a class="header-anchor" href="#與-harness-設計的對應" aria-label="Permalink to &quot;與 Harness 設計的對應&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Eugene Yan 的 Pattern</th><th>本 Workspace 的實現</th></tr></thead><tbody><tr><td>Evals</td><td>/deep-review skill + healthcheck.sh</td></tr><tr><td>RAG</td><td>WebFetch + researcher agent</td></tr><tr><td>Caching</td><td>prompt caching 架構規則（context-management.md）</td></tr><tr><td>Guardrails</td><td>security-hygiene.md + PreToolUse hook</td></tr><tr><td>Collect Feedback</td><td>Ratchet + Known Gotchas 更新</td></tr></tbody></table>',25)])])}const m=e(s,[["render",d]]);export{u as __pageData,m as default};
